var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"호오, 취미가 나쁘네. 이런 곳에서 관찰자 행세나 하고.","JPN":"ほう、趣味が悪いな。こんな所で観測者のふりをしているとは。","ENG":"Ho-oh, what a horrible hobby, pretending to be the observer in a place like this.","TWN":"呵，品味真差，在這種地方當一個觀察者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"그래서 내게 무슨 용무지?","JPN":"それで、私に何の用だ？","ENG":"So, why did you want to see me?","TWN":"怎麼樣？找我有什麼事？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"흠, 종신계약? 꽤 재밌는 걸 하고 있잖아?","JPN":"ふむ。終身契約？　なかなか面白いことをやっているじゃないか。","ENG":"Hmm, a lifetime contract? Sounds quite interesting, I must say.","TWN":"哼，終身契約？好像蠻有意思的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"지금까지 많은 사람과 계약을 맺어왔지만…… 반대로 계약을 권유받을 줄은 몰랐어.","JPN":"これまで多くの者と契約してきたが……、契約を持ちかけられるとはな。","ENG":"I've formed contracts with many people before, but... never have I been offered one.","TWN":"從來都是我主動找人簽訂契約……沒想到現在是反過來有人主動找上我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"그래서? 그 계약인지 뭔지로 너는 나에게 무엇을 줄 수 있지?","JPN":"で？　その契約とやらで、お前は私に何をくれるんだ？","ENG":"So? This contract of yours, what's in it for me?","TWN":"所以呢？簽下這份契約後，我可以從你身上得到什麼好處？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"후후, 무슨 소리를 하는 거야, 직책 같은 건 귀찮을 뿐인 걸.","JPN":"ふふっ、何を言っている。役職なんてのは面倒なだけだ。","ENG":"Fu fu, you can't be serious. Positions are just a bother.","TWN":"呵呵，你在說什麼？職稱什麼的好麻煩。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"하지만…… 매일 피자를 제공해준다는 말은 썩 나쁘지 않은 제안이로군.","JPN":"しかし……毎日ピザを提供するというのは悪くない条件だ。","ENG":"However... If you're willing to provide me with pizza every day, I don't think it's a bad deal.","TWN":"不過……每天都有供應披薩，這個條件很吸引人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"여기에 있는 동안에는 어울려주도록 할까?","JPN":"ここにいる間だけは付き合ってやるとするか。","ENG":"Then, maybe I'll stick along for a bit.","TWN":"我在這裡的這段時間，就和你合作吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"하지만 착각하지 마. 이건 계약이 아니니까.","JPN":"だが、勘違いするなよ。これは契約ではない。","ENG":"But don't be mistaken. This is not a contract.","TWN":"但你別誤會，這可不是契約。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"지금의 나는 이미 다른 녀석과 계약을 맺고 있는 몸이니까 말이지.","JPN":"今の私は既に別のやつと契約を交わしている身なんでな。","ENG":"I already have a contract with someone else right now.","TWN":"因為我已經先和別人簽訂契約了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};